    ++(2,0) coordinate (se)
  ;
   \path 
    (n/a) ++(4,0) coordinate[label={[text depth=0pt]above:$ \widetilde { p } $}] (n/p)
  ;
   \draw [spath/save=wire] (n/a) to[out=-90,in=90] (s/u);
